123→/// Geographic coordinates (WGS 84).
124→#[derive(Debug, Clone, Serialize, Deserialize)]
125→pub struct GeoLocation {
126→    pub latitude: f64,
127→    pub longitude: f64,
128→    /// Human-readable place name from reverse geocoding (e.g. "Noe Valley, San Francisco, CA").
129→    #[serde(default, skip_serializing_if = "Option::is_none")]
130→    pub place: Option<String>,
131→    /// Unix epoch seconds when the location was last updated.
132→    #[serde(default, skip_serializing_if = "Option::is_none")]
133→    pub updated_at: Option<i64>,
134→}
135→
136→impl GeoLocation {
137→    /// Create a new `GeoLocation` stamped with the current time.
138→    pub fn now(latitude: f64, longitude: f64, place: Option<String>) -> Self {
139→        let ts = std::time::SystemTime::now()
140→            .duration_since(std::time::UNIX_EPOCH)
141→            .unwrap_or_default()
142→            .as_secs() as i64;
143→        Self {
144→            latitude,
145→            longitude,
146→            place,
147→            updated_at: Some(ts),
148→        }
149→    }
150→}
151→
152→impl std::fmt::Display for GeoLocation {
153→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
154→        if let Some(ref place) = self.place {
155→            write!(f, "{place}")?;
156→        } else {
157→            write!(f, "{},{}", self.latitude, self.longitude)?;
158→        }
159→        if let Some(ts) = self.updated_at {
160→            let now = std::time::SystemTime::now()
161→                .duration_since(std::time::UNIX_EPOCH)
162→                .unwrap_or_default()
163→                .as_secs() as i64;
164→            let age_secs = now.saturating_sub(ts);
165→            let age_str = if age_secs < 60 {
166→                "just now".to_string()
167→            } else if age_secs < 3600 {
168→                format!("{}m ago", age_secs / 60)
169→            } else if age_secs < 86400 {
170→                format!("{}h ago", age_secs / 3600)
171→            } else {
172→                format!("{}d ago", age_secs / 86400)
173→            };
174→            write!(f, " (updated {age_str})")?;
175→        }
176→        Ok(())
177→    }
178→}
