230→    pub providers: ProvidersConfig,
231→    pub chat: ChatConfig,
232→    pub tools: ToolsConfig,
233→    pub agents: AgentsConfig,
234→    pub skills: SkillsConfig,
235→    pub mcp: McpConfig,
236→    pub channels: ChannelsConfig,
237→    pub tls: TlsConfig,
