251→    pub webhooks: WebhooksConfig,
252→    /// Per-model overrides that apply across all providers.
253→    ///
254→    /// Keys are normalized model IDs. Provider-scoped overrides
255→    /// (`[providers.<name>.models.<id>]`) take precedence over these.
256→    ///
257→    /// ```toml
258→    /// [models.claude-opus-4-6]
259→    /// context_window = 1_000_000
260→    /// ```
261→    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
262→    pub models: HashMap<String, ModelOverride>,
263→    /// Upstream HTTP/SOCKS proxy for all outbound requests.
264→    ///
265→    /// Supports `http://`, `https://`, `socks5://`, and `socks5h://` schemes.
266→    /// Proxy authentication via URL: `http://user:pass@host:port`.
267→    /// When set, overrides the `HTTP_PROXY`/`HTTPS_PROXY`/`ALL_PROXY` environment
268→    /// variables for all traffic (providers, channels, tools, OAuth).
269→    /// Localhost/loopback addresses are automatically excluded (`no_proxy`).
270→    #[serde(
271→        default,
272→        skip_serializing_if = "Option::is_none",
273→        serialize_with = "crate::schema::serialize_option_secret",
274→        deserialize_with = "crate::schema::deserialize_option_secret"
275→    )]
276→    pub upstream_proxy: Option<Secret<String>>,
277→    /// Environment variables injected into the Moltis process at startup.
278→    /// Useful for API keys in Docker where you can't easily set env vars.
279→    /// Process env vars take precedence (existing vars are not overwritten).
280→    #[serde(default)]
281→    pub env: HashMap<String, String>,
282→}
