292→fn serialize_option_secret<S: serde::Serializer>(
293→    secret: &Option<Secret<String>>,
294→    serializer: S,
295→) -> Result<S::Ok, S::Error> {
296→    match secret {
297→        Some(s) => serializer.serialize_some(s.expose_secret()),
298→        None => serializer.serialize_none(),
299→    }
300→}
301→
302→fn deserialize_option_secret<'de, D>(deserializer: D) -> Result<Option<Secret<String>>, D::Error>
303→where
304→    D: Deserializer<'de>,
305→{
306→    let opt: Option<String> = Option::deserialize(deserializer)?;
307→    Ok(opt.map(Secret::new))
308→}
