109→/// Check provider names under `[providers]` and warn about unknown ones.
110→pub(super) fn check_provider_names(
111→    providers: &toml::map::Map<String, toml::Value>,
112→    diagnostics: &mut Vec<Diagnostic>,
113→) {
114→    for name in providers.keys() {
115→        if PROVIDERS_META_KEYS.contains(&name.as_str()) {
116→            continue;
117→        }
118→        // Custom providers (user-added OpenAI-compatible endpoints) are valid.
119→        if name.starts_with("custom-") {
120→            continue;
121→        }
122→        if !KNOWN_PROVIDER_NAMES.contains(&name.as_str()) {
123→            let suggestion = suggest(name, KNOWN_PROVIDER_NAMES, 3);
124→            let msg = if let Some(s) = suggestion {
125→                format!("unknown provider name (did you mean \"{s}\"?)")
126→            } else {
127→                "unknown provider name (custom providers are valid, but check for typos)".into()
128→            };
129→            diagnostics.push(Diagnostic {
130→                severity: Severity::Warning,
131→                category: "unknown-provider",
132→                path: format!("providers.{name}"),
133→                message: msg,
134→            });
135→        }
136→    }
137→}
138→
139→/// Run semantic checks on a successfully parsed config.
140→pub(super) fn check_semantic_warnings(config: &MoltisConfig, diagnostics: &mut Vec<Diagnostic>) {
141→    let is_localhost = config.server.bind == "127.0.0.1"
142→        || config.server.bind == "localhost"
143→        || config.server.bind == "::1";
144→
145→    // auth.disabled + non-localhost
146→    if config.auth.disabled && !is_localhost {
147→        diagnostics.push(Diagnostic {
148→            severity: Severity::Warning,
149→            category: "security",
150→            path: "auth".into(),
151→            message: format!(
152→                "authentication is disabled while binding to {}",
153→                config.server.bind
154→            ),
155→        });
156→    }
157→
158→    // TLS disabled + non-localhost
159→    if !config.tls.enabled && !is_localhost {
160→        diagnostics.push(Diagnostic {
161→            severity: Severity::Warning,
162→            category: "security",
163→            path: "tls".into(),
164→            message: format!("TLS is disabled while binding to {}", config.server.bind),
165→        });
166→    }
167→
168→    // TLS cert without key or vice versa
169→    let has_cert = config.tls.cert_path.is_some();
170→    let has_key = config.tls.key_path.is_some();
171→    if has_cert && !has_key {
172→        diagnostics.push(Diagnostic {
173→            severity: Severity::Error,
174→            category: "security",
175→            path: "tls".into(),
176→            message: "tls.cert_path is set but tls.key_path is missing".into(),
177→        });
178→    }
179→    if has_key && !has_cert {
180→        diagnostics.push(Diagnostic {
181→            severity: Severity::Error,
182→            category: "security",
183→            path: "tls".into(),
184→            message: "tls.key_path is set but tls.cert_path is missing".into(),
185→        });
186→    }
187→
188→    // Sandbox mode off
189→    if config.tools.exec.sandbox.mode == "off" {
190→        diagnostics.push(Diagnostic {
191→            severity: Severity::Warning,
192→            category: "security",
193→            path: "tools.exec.sandbox.mode".into(),
194→            message: "sandbox mode is disabled — commands run without isolation".into(),
195→        });
196→    }
197→
198→    // tools.fs: must_read_before_write requires track_reads
199→    if config.tools.fs.must_read_before_write && !config.tools.fs.track_reads {
200→        diagnostics.push(Diagnostic {
201→            severity: Severity::Error,
202→            category: "invalid-value",
203→            path: "tools.fs".into(),
204→            message: "must_read_before_write=true requires track_reads=true".into(),
205→        });
206→    }
207→
208→    // tools.fs.workspace_root must be absolute when set
209→    if let Some(ref root) = config.tools.fs.workspace_root
210→        && !Path::new(root).is_absolute()
211→    {
212→        diagnostics.push(Diagnostic {
213→            severity: Severity::Error,
214→            category: "invalid-value",
215→            path: "tools.fs.workspace_root".into(),
216→            message: format!("workspace_root must be an absolute path (got '{root}')"),
217→        });
218→    }
219→
220→    // tools.fs.allow_paths / deny_paths entries should be absolute
221→    for (idx, entry) in config.tools.fs.allow_paths.iter().enumerate() {
222→        if !entry.starts_with('/') && !entry.starts_with("**") {
223→            diagnostics.push(Diagnostic {
224→                severity: Severity::Warning,
225→                category: "invalid-value",
226→                path: format!("tools.fs.allow_paths[{idx}]"),
227→                message: format!(
228→                    "allow_paths entries should be absolute path globs starting with '/' (got '{entry}')"
229→                ),
230→            });
231→        }
232→    }
233→    for (idx, entry) in config.tools.fs.deny_paths.iter().enumerate() {
234→        if !entry.starts_with('/') && !entry.starts_with("**") {
235→            diagnostics.push(Diagnostic {
236→                severity: Severity::Warning,
237→                category: "invalid-value",
238→                path: format!("tools.fs.deny_paths[{idx}]"),
239→                message: format!(
240→                    "deny_paths entries should be absolute path globs starting with '/' (got '{entry}')"
241→                ),
242→            });
243→        }
244→    }
245→
246→    // server.external_url: must use http:// or https:// scheme.
247→    if let Some(ref url) = config.server.external_url {
248→        if !url.starts_with("http://") && !url.starts_with("https://") {
249→            let scheme = url.split("://").next().unwrap_or("<unknown>");
250→            diagnostics.push(Diagnostic {
251→                severity: Severity::Error,
252→                category: "invalid-value",
253→                path: "server.external_url".into(),
254→                message: format!(
255→                    "server.external_url must use http:// or https:// scheme (got \"{scheme}://\")"
256→                ),
257→            });
258→        }
259→        if url.ends_with('/') {
260→            diagnostics.push(Diagnostic {
261→                severity: Severity::Warning,
262→                category: "invalid-value",
263→                path: "server.external_url".into(),
264→                message: "server.external_url has a trailing slash; WebAuthn origins must not end with '/' (it will be stripped at runtime)".into(),
265→            });
266→        }
267→    }
268→
269→    // upstream_proxy: must be a valid URL with a supported scheme.
270→    if let Some(ref proxy) = config.upstream_proxy {
271→        let url = proxy.expose_secret();
272→        let valid = url.starts_with("http://")
273→            || url.starts_with("https://")
274→            || url.starts_with("socks5://")
275→            || url.starts_with("socks5h://");
276→        if !valid {
277→            // Extract only the scheme portion (before "://") to avoid leaking
278→            // credentials that may be embedded in the URL.
279→            let scheme = url.split("://").next().unwrap_or("<unknown>");
280→            diagnostics.push(Diagnostic {
281→                severity: Severity::Error,
282→                category: "invalid-value",
283→                path: "upstream_proxy".into(),
284→                message: format!(
285→                    "upstream_proxy must use http://, https://, socks5://, or socks5h:// scheme (got \"{scheme}://\")"
286→                ),
287→            });
288→        }
289→    }
290→
291→    // Loop limit must be positive to avoid immediate run failures.
292→    if config.tools.agent_max_iterations == 0 {
293→        diagnostics.push(Diagnostic {
294→            severity: Severity::Error,
295→            category: "invalid-value",
296→            path: "tools.agent_max_iterations".into(),
297→            message: "tools.agent_max_iterations must be at least 1".into(),
298→        });
299→    }
300→
301→    // A zero workspace file limit would silently drop all AGENTS.md / TOOLS.md content.
302→    if config.chat.workspace_file_max_chars == 0 {
303→        diagnostics.push(Diagnostic {
304→            severity: Severity::Warning,
305→            category: "invalid-value",
306→            path: "chat.workspace_file_max_chars".into(),
307→            message: "chat.workspace_file_max_chars is 0 — AGENTS.md and TOOLS.md will be empty in the prompt".into(),
308→        });
309→    }
310→
311→    // Compaction config sanity.
312→    let compaction = &config.chat.compaction;
313→    if !(0.1..=0.95).contains(&compaction.threshold_percent) {
314→        diagnostics.push(Diagnostic {
315→            severity: Severity::Warning,
316→            category: "invalid-value",
317→            path: "chat.compaction.threshold_percent".into(),
318→            message: format!(
319→                "chat.compaction.threshold_percent = {} is outside the supported 0.1–0.95 range; the default (0.95) will be used",
320→                compaction.threshold_percent
321→            ),
322→        });
323→    }
324→    if !(0.05..=0.80).contains(&compaction.tail_budget_ratio) {
325→        diagnostics.push(Diagnostic {
326→            severity: Severity::Warning,
327→            category: "invalid-value",
328→            path: "chat.compaction.tail_budget_ratio".into(),
329→            message: format!(
330→                "chat.compaction.tail_budget_ratio = {} is outside the supported 0.05–0.80 range; the default (0.20) will be used",
331→                compaction.tail_budget_ratio
332→            ),
333→        });
334→    }
335→    if compaction.protect_head > 32 {
336→        diagnostics.push(Diagnostic {
337→            severity: Severity::Warning,
338→            category: "invalid-value",
339→            path: "chat.compaction.protect_head".into(),
340→            message: "chat.compaction.protect_head > 32 will leave little room for the compacted middle region on typical sessions".into(),
341→        });
342→    }
343→    // All four CompactionMode variants are now implemented. Any future
344→    // "not-implemented" markers would go here; leave the match explicit so
345→    // adding a new variant forces a decision at compile time.
346→    match compaction.mode {
347→        crate::schema::CompactionMode::Deterministic
348→        | crate::schema::CompactionMode::RecencyPreserving
349→        | crate::schema::CompactionMode::Structured
350→        | crate::schema::CompactionMode::LlmReplace => {},
351→    }
352→
353→    if config.mcp.request_timeout_secs == 0 {
354→        diagnostics.push(Diagnostic {
355→            severity: Severity::Error,
356→            category: "invalid-value",
357→            path: "mcp.request_timeout_secs".into(),
358→            message: "mcp.request_timeout_secs must be at least 1".into(),
359→        });
360→    }
361→
362→    for (name, server) in &config.mcp.servers {
363→        if server.request_timeout_secs == Some(0) {
364→            diagnostics.push(Diagnostic {
365→                severity: Severity::Error,
366→                category: "invalid-value",
367→                path: format!("mcp.servers.{name}.request_timeout_secs"),
368→                message: "mcp server request_timeout_secs must be at least 1".into(),
369→            });
370→        }
371→
372→        if !server.transport.is_empty()
373→            && !matches!(
374→                server.transport.as_str(),
375→                "stdio" | "sse" | "streamable-http" | "streamable_http" | "http"
376→            )
377→        {
378→            diagnostics.push(Diagnostic {
379→                severity: Severity::Warning,
380→                category: "invalid-value",
381→                path: format!("mcp.servers.{name}.transport"),
382→                message: format!(
383→                    "unknown transport type \"{}\"; expected \"stdio\", \"sse\", or \"streamable-http\"",
384→                    server.transport
385→                ),
386→            });
387→        }
388→    }
389→
390→    // Firecrawl as search provider requires an API key.  We cannot check
391→    // the FIRECRAWL_API_KEY env var here (static validation), so only emit
392→    // an Info-level hint when neither config path supplies a key.
393→    if config.tools.web.search.provider == crate::schema::SearchProvider::Firecrawl
394→        && config.tools.web.firecrawl.api_key.is_none()
395→        && config.tools.web.search.api_key.is_none()
396→        && !config.tools.web.search.duckduckgo_fallback
397→    {
398→        diagnostics.push(Diagnostic {
399→            severity: Severity::Info,
400→            category: "unknown-provider",
401→            path: "tools.web.search.provider".into(),
402→            message: "search provider is 'firecrawl' but no API key found in config \
403→                      (may be supplied at runtime via FIRECRAWL_API_KEY env var)"
404→                .into(),
405→        });
406→    }
407→
408→    // agents.default_preset should reference an existing preset key.
409→    if let Some(default_preset) = config.agents.default_preset.as_deref()
410→        && !config.agents.presets.contains_key(default_preset)
411→    {
412→        diagnostics.push(Diagnostic {
413→            severity: Severity::Warning,
414→            category: "unknown-field",
415→            path: "agents.default_preset".into(),
416→            message: format!(
417→                "default preset \"{default_preset}\" is not defined in agents.presets"
418→            ),
419→        });
420→    }
421→
422→    // Silent-misconfiguration trap: `[agents.presets.*]` tool policies apply
423→    // ONLY to sub-agents spawned via `spawn_agent`. They do NOT filter tools
424→    // for the main agent session — that is controlled exclusively by
425→    // `[tools.policy]`. Users hardening their deployment often put a deny
426→    // list under a preset and expect it to apply to the main session; it
427→    // silently doesn't. Warn when at least one preset declares
428→    // `tools.allow`/`tools.deny` while `[tools.policy]` is entirely empty.
429→    {
430→        let main_policy_empty = config.tools.policy.allow.is_empty()
431→            && config.tools.policy.deny.is_empty()
432→            && config.tools.policy.profile.is_none();
433→        if main_policy_empty {
434→            let mut offending: Vec<&str> = config
435→                .agents
436→                .presets
437→                .iter()
438→                .filter(|(_, preset)| {
439→                    !preset.tools.allow.is_empty() || !preset.tools.deny.is_empty()
440→                })
441→                .map(|(name, _)| name.as_str())
442→                .collect();
443→            if !offending.is_empty() {
444→                offending.sort_unstable();
445→                let quoted: Vec<String> =
446→                    offending.iter().map(|name| format!("\"{name}\"")).collect();
447→                diagnostics.push(Diagnostic {
448→                    severity: Severity::Warning,
449→                    category: "security",
450→                    path: "agents.presets".into(),
451→                    message: format!(
452→                        "preset(s) [{}] declare tools.allow/tools.deny, but \
453→                         [tools.policy] is empty. Preset tool policies apply \
454→                         ONLY to sub-agents spawned via the spawn_agent tool; \
455→                         they do NOT filter tools for the main agent session. \
456→                         To allow/deny tools for the main session, set \
457→                         tools.policy.allow, tools.policy.deny, or \
458→                         tools.policy.profile.",
459→                        quoted.join(", ")
460→                    ),
461→                });
462→            }
463→        }
464→    }
465→
466→    // agents.presets.*.reasoning_effort is now a typed enum (ReasoningEffort)
467→    // and validated at deserialization time (step 4). No semantic check needed.
468→
469→    // SSRF allowlist CIDR validation
470→    for (idx, entry) in config.tools.web.fetch.ssrf_allowlist.iter().enumerate() {
471→        if entry.parse::<ipnet::IpNet>().is_err() {
472→            diagnostics.push(Diagnostic {
473→                severity: Severity::Error,
474→                category: "security",
475→                path: format!("tools.web.fetch.ssrf_allowlist[{idx}]"),
476→                message: format!(
477→                    "\"{entry}\" is not a valid CIDR range (expected e.g. \"172.22.0.0/16\")"
478→                ),
479→            });
480→        }
481→    }
482→    if !config.tools.web.fetch.ssrf_allowlist.is_empty() {
483→        diagnostics.push(Diagnostic {
484→            severity: Severity::Warning,
485→            category: "security",
486→            path: "tools.web.fetch.ssrf_allowlist".into(),
487→            message: "ssrf_allowlist is set — SSRF protection is relaxed for the listed ranges. Ensure these are trusted networks.".into(),
488→        });
489→    }
490→
491→    // Unknown tool_mode values on provider entries
492→    // Note: serde rejects truly invalid values at deserialization, but if a
493→    // provider entry somehow comes through with a non-standard string we still
494→    // want to warn at the TOML level.  The enum is auto/native/text/off.
495→
496→    // Unknown channel types in channels.offered — accept built-in types plus
497→    // any dynamically configured types from `[channels.<type>]` sections.
498→    let mut valid_channel_types: Vec<&str> = crate::schema::KNOWN_CHANNEL_TYPES.to_vec();
499→    for ct in config.channels.extra.keys() {
500→        valid_channel_types.push(ct.as_str());
501→    }
502→    for (idx, entry) in config.channels.offered.iter().enumerate() {
503→        if !valid_channel_types.contains(&entry.as_str()) {
504→            diagnostics.push(Diagnostic {
505→                severity: Severity::Warning,
506→                category: "unknown-field",
507→                path: format!("channels.offered[{idx}]"),
508→                message: format!(
509→                    "unknown channel type \"{entry}\"; expected one of: {}",
510→                    valid_channel_types.join(", ")
511→                ),
512→            });
513→        }
514→    }
515→
516→    // Unknown tailscale mode
517→    let valid_ts_modes = ["off", "serve", "funnel"];
518→    if !valid_ts_modes.contains(&config.tailscale.mode.as_str()) {
519→        diagnostics.push(Diagnostic {
520→            severity: Severity::Warning,
521→            category: "unknown-field",
522→            path: "tailscale.mode".into(),
523→            message: format!(
524→                "unknown tailscale mode \"{}\"; expected one of: {}",
525→                config.tailscale.mode,
526→                valid_ts_modes.join(", ")
527→            ),
528→        });
529→    }
530→
531→    if config.ngrok.enabled && config.auth.disabled {
532→        diagnostics.push(Diagnostic {
533→            severity: Severity::Warning,
534→            category: "security",
535→            path: "ngrok.enabled".into(),
536→            message: "ngrok is enabled while auth.disabled is true; remote visitors will be blocked with setup required until authentication is configured".into(),
537→        });
538→    }
539→
540→    // Unknown sandbox backend
541→    let valid_sandbox_backends = [
542→        "auto",
543→        "docker",
544→        "podman",
545→        "apple-container",
546→        "restricted-host",
547→        "wasm",
548→    ];
549→    if !valid_sandbox_backends.contains(&config.tools.exec.sandbox.backend.as_str()) {
550→        diagnostics.push(Diagnostic {
551→            severity: Severity::Warning,
552→            category: "unknown-field",
553→            path: "tools.exec.sandbox.backend".into(),
554→            message: format!(
555→                "unknown sandbox backend \"{}\"; expected one of: {}",
556→                config.tools.exec.sandbox.backend,
557→                valid_sandbox_backends.join(", ")
558→            ),
559→        });
560→    }
561→
562→    // Unknown sandbox network policy
563→    if !config.tools.exec.sandbox.network.is_empty() {
564→        let valid_network_policies = ["blocked", "trusted", "bypass"];
565→        if !valid_network_policies.contains(&config.tools.exec.sandbox.network.as_str()) {
566→            diagnostics.push(Diagnostic {
567→                severity: Severity::Warning,
568→                category: "unknown-field",
569→                path: "tools.exec.sandbox.network".into(),
570→                message: format!(
571→                    "unknown sandbox network policy \"{}\"; expected one of: {}",
572→                    config.tools.exec.sandbox.network,
573→                    valid_network_policies.join(", ")
574→                ),
575→            });
576→        }
577→    }
578→
579→    // Unknown CalDAV provider
580→    let valid_caldav_providers = ["fastmail", "icloud", "generic"];
581→    for (name, account) in &config.caldav.accounts {
582→        if let Some(ref provider) = account.provider
583→            && !valid_caldav_providers.contains(&provider.as_str())
584→        {
585→            diagnostics.push(Diagnostic {
586→                severity: Severity::Warning,
587→                category: "unknown-field",
588→                path: format!("caldav.accounts.{name}.provider"),
589→                message: format!(
590→                    "unknown CalDAV provider \"{provider}\"; expected one of: {}",
591→                    valid_caldav_providers.join(", ")
592→                ),
593→            });
594→        }
595→    }
596→
597→    // Unknown exec host
598→    let valid_exec_hosts = ["local", "node", "ssh"];
599→    if !valid_exec_hosts.contains(&config.tools.exec.host.as_str()) {
600→        diagnostics.push(Diagnostic {
601→            severity: Severity::Warning,
602→            category: "unknown-field",
603→            path: "tools.exec.host".into(),
604→            message: format!(
605→                "unknown exec host \"{}\"; expected one of: {}",
606→                config.tools.exec.host,
607→                valid_exec_hosts.join(", ")
608→            ),
609→        });
610→    }
611→
612→    // Warn if host=node but no node specified
613→    if config.tools.exec.host == "node" && config.tools.exec.node.is_none() {
614→        diagnostics.push(Diagnostic {
615→            severity: Severity::Warning,
616→            category: "unknown-field",
617→            path: "tools.exec.node".into(),
618→            message: "tools.exec.host is \"node\" but no default node is specified; commands will fail unless a node connects".into(),
619→        });
620→    }
621→
622→    if config.tools.exec.host == "ssh" && config.tools.exec.ssh_target.is_none() {
623→        diagnostics.push(Diagnostic {
624→            severity: Severity::Warning,
625→            category: "unknown-field",
626→            path: "tools.exec.ssh_target".into(),
627→            message:
628→                "tools.exec.host is \"ssh\" but no SSH target is specified; commands will fail"
629→                    .into(),
630→        });
631→    }
632→
633→    // Unknown exec security level
634→    let valid_security_levels = ["allowlist", "permissive", "strict"];
635→    if !valid_security_levels.contains(&config.tools.exec.security_level.as_str()) {
636→        diagnostics.push(Diagnostic {
637→            severity: Severity::Warning,
638→            category: "unknown-field",
639→            path: "tools.exec.security_level".into(),
640→            message: format!(
641→                "unknown security level \"{}\"; expected one of: {}",
642→                config.tools.exec.security_level,
643→                valid_security_levels.join(", ")
644→            ),
645→        });
646→    }
647→
648→    // Unknown voice TTS providers list values
649→    let valid_voice_tts_providers = [
650→        "elevenlabs",
651→        "openai",
652→        "openai-tts",
653→        "google",
654→        "google-tts",
655→        "piper",
656→        "coqui",
657→    ];
658→    for (idx, provider) in config.voice.tts.providers.iter().enumerate() {
659→        if !valid_voice_tts_providers.contains(&provider.as_str()) {
660→            diagnostics.push(Diagnostic {
661→                severity: Severity::Warning,
662→                category: "unknown-field",
663→                path: format!("voice.tts.providers[{idx}]"),
664→                message: format!(
665→                    "unknown TTS provider \"{provider}\"; expected one of: {}",
666→                    valid_voice_tts_providers.join(", ")
667→                ),
668→            });
669→        }
670→    }
671→
672→    // Unknown voice STT providers list values
673→    let valid_voice_stt_providers = [
674→        "whisper",
675→        "groq",
676→        "deepgram",
677→        "google",
678→        "mistral",
679→        "elevenlabs",
680→        "elevenlabs-stt",
681→        "voxtral-local",
682→        "whisper-cli",
683→        "sherpa-onnx",
684→    ];
685→    for (idx, provider) in config.voice.stt.providers.iter().enumerate() {
686→        if !valid_voice_stt_providers.contains(&provider.as_str()) {
687→            diagnostics.push(Diagnostic {
688→                severity: Severity::Warning,
689→                category: "unknown-field",
690→                path: format!("voice.stt.providers[{idx}]"),
691→                message: format!(
692→                    "unknown STT provider \"{provider}\"; expected one of: {}",
693→                    valid_voice_stt_providers.join(", ")
694→                ),
695→            });
696→        }
697→    }
698→
699→    // Unknown hook event names
700→    let valid_hook_events = [
701→        "BeforeAgentStart",
702→        "AgentEnd",
703→        "BeforeLLMCall",
704→        "AfterLLMCall",
705→        "BeforeCompaction",
706→        "AfterCompaction",
707→        "MessageReceived",
708→        "MessageSending",
709→        "MessageSent",
710→        "BeforeToolCall",
711→        "AfterToolCall",
712→        "ToolResultPersist",
713→        "SessionStart",
714→        "SessionEnd",
715→        "GatewayStart",
716→        "GatewayStop",
717→        "Command",
718→    ];
719→    if let Some(ref hooks_config) = config.hooks {
720→        for (hook_idx, hook) in hooks_config.hooks.iter().enumerate() {
721→            for (ev_idx, event) in hook.events.iter().enumerate() {
722→                if !valid_hook_events.contains(&event.as_str()) {
723→                    diagnostics.push(Diagnostic {
724→                        severity: Severity::Warning,
725→                        category: "unknown-field",
726→                        path: format!("hooks.hooks[{hook_idx}].events[{ev_idx}]"),
727→                        message: format!(
728→                            "unknown hook event \"{event}\"; expected one of: {}",
729→                            valid_hook_events.join(", ")
730→                        ),
731→                    });
732→                }
733→            }
734→        }
735→    }
736→
737→    // Browser profile_dir should be an absolute path
738→    if let Some(ref dir) = config.tools.browser.profile_dir
739→        && !Path::new(dir).is_absolute()
740→    {
741→        diagnostics.push(Diagnostic {
742→            severity: Severity::Warning,
743→            category: "invalid-value",
744→            path: "tools.browser.profile_dir".into(),
745→            message: "profile_dir should be an absolute path".into(),
746→        });
747→    }
748→
749→    // port == 0
750→    if config.server.port == 0 {
751→        diagnostics.push(Diagnostic {
752→            severity: Severity::Info,
753→            category: "security",
754→            path: "server.port".into(),
755→            message: "port is 0; a random port will be assigned at startup".into(),
756→        });
757→    }
758→
759→    // Validate global model overrides.
760→    // Negative values are rejected by u32 deserialization (type error),
761→    // so we only need to guard zero and unusually large values here.
762→    for (model_id, override_cfg) in &config.models {
763→        validate_context_window(
764→            override_cfg.context_window,
765→            &format!("models.{model_id}.context_window"),
766→            diagnostics,
767→        );
768→    }
769→
770→    // Validate provider-scoped model overrides.
771→    for (provider_name, provider_entry) in &config.providers.providers {
772→        for (model_id, override_cfg) in &provider_entry.model_overrides {
773→            validate_context_window(
774→                override_cfg.context_window,
775→                &format!("providers.{provider_name}.model_overrides.{model_id}.context_window"),
776→                diagnostics,
777→            );
778→        }
779→    }
780→
781→    // tools: overflow_ratio must not be zero (budget becomes 0, every iteration fails)
782→    if config.tools.preemptive_overflow_ratio == 0 {
783→        diagnostics.push(Diagnostic {
784→            severity: Severity::Warning,
785→            category: "invalid-value",
786→            path: "tools.preemptive_overflow_ratio".into(),
787→            message: "preemptive_overflow_ratio = 0 means the overflow budget is always \
788→                      0 tokens; the agent loop will fail immediately on every iteration"
789→                .into(),
790→        });
791→    }
792→
793→    // tools: ratio fields should not exceed 100 (percentages)
794→    if config.tools.tool_result_compaction_ratio > 100 {
795→        diagnostics.push(Diagnostic {
796→            severity: Severity::Warning,
797→            category: "invalid-value",
798→            path: "tools.tool_result_compaction_ratio".into(),
799→            message: format!(
800→                "tool_result_compaction_ratio ({}) exceeds 100 — compaction will trigger on every iteration regardless of context usage",
801→                config.tools.tool_result_compaction_ratio
802→            ),
803→        });
804→    }
805→    if config.tools.preemptive_overflow_ratio > 100 {
806→        diagnostics.push(Diagnostic {
807→            severity: Severity::Warning,
808→            category: "invalid-value",
809→            path: "tools.preemptive_overflow_ratio".into(),
810→            message: format!(
811→                "preemptive_overflow_ratio ({}) exceeds 100 — overflow protection will always trigger",
812→                config.tools.preemptive_overflow_ratio
813→            ),
814→        });
815→    }
816→
817→    // tools: overflow_ratio must be greater than compaction_ratio
818→    if config.tools.tool_result_compaction_ratio > 0
819→        && config.tools.preemptive_overflow_ratio <= config.tools.tool_result_compaction_ratio
820→    {
821→        diagnostics.push(Diagnostic {
822→            severity: Severity::Warning,
823→            category: "invalid-value",
824→            path: "tools.preemptive_overflow_ratio".into(),
825→            message: format!(
826→                "preemptive_overflow_ratio ({}) should be greater than tool_result_compaction_ratio ({}) to avoid context overflow on every iteration",
827→                config.tools.preemptive_overflow_ratio, config.tools.tool_result_compaction_ratio
828→            ),
829→        });
830→    }
831→}
