833→/// Validate a `context_window` override value (optional field).
834→fn validate_context_window(value: Option<u32>, path: &str, diagnostics: &mut Vec<Diagnostic>) {
835→    let Some(cw) = value else {
836→        return;
837→    };
838→    if cw == 0 {
839→        diagnostics.push(Diagnostic {
840→            severity: Severity::Error,
841→            category: "invalid-value",
842→            path: path.into(),
843→            message: "context_window must be at least 1".into(),
844→        });
845→    } else if cw > 10_000_000 {
846→        diagnostics.push(Diagnostic {
847→            severity: Severity::Warning,
848→            category: "invalid-value",
849→            path: path.into(),
850→            message: format!("context_window is {cw}, which is unusually large (> 10M)"),
851→        });
852→    }
853→}
