855→/// Check that file paths referenced in TLS config exist on disk.
856→pub(super) fn check_file_references(
857→    toml_str: &str,
858→    _config_path: &Path,
859→    diagnostics: &mut Vec<Diagnostic>,
860→) {
861→    // Only check if we can parse the config
862→    let Ok(config) = toml::from_str::<MoltisConfig>(toml_str) else {
863→        return;
864→    };
865→
866→    let file_refs: &[(&str, &Option<String>)] = &[
867→        ("tls.cert_path", &config.tls.cert_path),
868→        ("tls.key_path", &config.tls.key_path),
869→        ("tls.ca_cert_path", &config.tls.ca_cert_path),
870→    ];
871→
872→    for (path_name, value) in file_refs {
873→        if let Some(file_path) = value {
874→            let p = Path::new(file_path);
875→            if !p.exists() {
876→                diagnostics.push(Diagnostic {
877→                    severity: Severity::Warning,
878→                    category: "file-ref",
879→                    path: (*path_name).into(),
880→                    message: format!("file not found: {file_path}"),
881→                });
882→            }
883→        }
884→    }
885→}
