387→#[async_trait]
388→impl Sandbox for DockerSandbox {
389→    fn backend_name(&self) -> &'static str {
390→        self.backend_label
391→    }
392→
393→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
394→        let name = self.container_name(id);
395→
396→        // Check if container already running.
397→        let check = tokio::process::Command::new(self.cli)
398→            .args(["inspect", "--format", "{{.State.Running}}", &name])
399→            .output()
400→            .await;
401→
402→        if let Ok(output) = check {
403→            let stdout = String::from_utf8_lossy(&output.stdout);
404→            if stdout.trim() == "true" {
405→                debug!(container = %name, "sandbox container already running");
406→                return Ok(());
407→            }
408→        }
409→
410→        // Resolve image first so we know whether it's prebuilt (affects hardening).
411→        let requested_image = image_override.unwrap_or_else(|| self.image());
412→        let image = self.resolve_local_image(requested_image).await?;
413→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
414→        debug!(container = %name, %image, is_prebuilt, "resolved sandbox image");
415→
416→        // Start a new container.
417→        info!(container = %name, %image, "starting new sandbox container");
418→        let mut args = vec![
419→            "run".to_string(),
420→            "-d".to_string(),
421→            "--name".to_string(),
422→            name.clone(),
423→        ];
424→
425→        args.extend(self.network_run_args());
426→
427→        if let Some(ref tz) = self.config.timezone {
428→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
429→        }
430→
431→        args.extend(self.resource_args());
432→        args.extend(Self::hardening_args(is_prebuilt, self.kind));
433→        args.extend(self.workspace_args());
434→        args.extend(self.home_persistence_args(id)?);
435→
436→        args.push(image.clone());
437→        args.extend(["sleep".to_string(), "infinity".to_string()]);
438→
439→        let output = tokio::process::Command::new(self.cli)
440→            .args(&args)
441→            .output()
442→            .await?;
443→
444→        if !output.status.success() {
445→            let stderr = String::from_utf8_lossy(&output.stderr);
446→            return Err(Error::message(format!(
447→                "{} run failed: {}",
448→                self.cli,
449→                stderr.trim()
450→            )));
451→        }
452→
453→        // Skip provisioning if the image is a pre-built instance sandbox image
454→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
455→        if !is_prebuilt {
456→            let needs_provisioning = {
457→                let mut provisioned = self.provisioned.lock().await;
458→                if provisioned.contains(&name) {
459→                    false
460→                } else {
461→                    provisioned.insert(name.clone());
462→                    true
463→                }
464→            };
465→            if needs_provisioning {
466→                if let Err(e) = provision_packages(self.cli, &name, &self.config.packages).await {
467→                    self.provisioned.lock().await.remove(&name);
468→                    return Err(e);
469→                }
470→            } else {
471→                debug!(
472→                    container = %name,
473→                    "skipping provisioning, already completed for container"
474→                );
475→            }
476→        }
477→
478→        Ok(())
479→    }
480→
481→    async fn build_image(
482→        &self,
483→        base: &str,
484→        packages: &[String],
485→    ) -> Result<Option<BuildImageResult>> {
486→        if packages.is_empty() {
487→            return Ok(None);
488→        }
489→
490→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
491→
492→        // Check if image already exists.
493→        if sandbox_image_exists(self.cli, &tag).await {
494→            info!(
495→                tag,
496→                "pre-built sandbox image already exists, skipping build"
497→            );
498→            return Ok(Some(BuildImageResult { tag, built: false }));
499→        }
500→
501→        // Generate Dockerfile in a temp dir.
502→        let tmp_dir =
503→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
504→        std::fs::create_dir_all(&tmp_dir)?;
505→
506→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
507→        let dockerfile = sandbox_image_dockerfile(base, packages);
508→        let dockerfile_path = tmp_dir.join("Dockerfile");
509→        std::fs::write(&dockerfile_path, &dockerfile)?;
510→
511→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
512→
513→        let output = tokio::process::Command::new(self.cli)
514→            .args(["build", "-t", &tag, "-f"])
515→            .arg(&dockerfile_path)
516→            .arg(&tmp_dir)
517→            .stdout(std::process::Stdio::piped())
518→            .stderr(std::process::Stdio::piped())
519→            .output()
520→            .await;
521→
522→        let output = output?;
523→        if !output.status.success() {
524→            let _ = std::fs::remove_dir_all(&tmp_dir);
525→            let stdout = String::from_utf8_lossy(&output.stdout);
526→            let stderr = String::from_utf8_lossy(&output.stderr);
527→            warn!(
528→                tag,
529→                stdout = %tail_lines(&stdout, 20),
530→                stderr = %stderr.trim(),
531→                "{} build failed",
532→                self.cli,
533→            );
534→            return Err(Error::message(format!(
535→                "{} build failed for {tag}: {}",
536→                self.cli,
537→                stderr.trim()
538→            )));
539→        }
540→
541→        let stdout = String::from_utf8_lossy(&output.stdout);
542→        debug!(tag, output = %tail_lines(&stdout, 20), "docker build output");
543→
544→        // Podman with BuildKit: the build may succeed (exit 0) but leave the
545→        // image in BuildKit's internal cache instead of the Podman store.
546→        // Verify the image is actually present and recover if not.
547→        if self.kind == BackendKind::Podman && !sandbox_image_exists(self.cli, &tag).await {
548→            warn!(
549→                tag,
550→                "podman build succeeded but image missing from store \
551→                 (likely BuildKit delegation), exporting via tarball"
552→            );
553→            let export_result = self
554→                .export_buildkit_image_to_store(&tag, &dockerfile_path, &tmp_dir)
555→                .await;
556→            // Clean up temp dir regardless of export result.
557→            let _ = std::fs::remove_dir_all(&tmp_dir);
558→            export_result?;
559→        } else {
560→            let _ = std::fs::remove_dir_all(&tmp_dir);
561→        }
562→
563→        info!(tag, "pre-built sandbox image ready");
564→        Ok(Some(BuildImageResult { tag, built: true }))
565→    }
566→
567→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
568→        let name = self.container_name(id);
569→
570→        let mut args = vec!["exec".to_string()];
571→
572→        if let Some(ref dir) = opts.working_dir {
573→            args.extend(["-w".to_string(), dir.display().to_string()]);
574→        }
575→
576→        // Inject proxy env vars so traffic routes through the trusted-network
577→        // proxy running on the host.
578→        args.extend(self.proxy_exec_env_args());
579→
580→        for (k, v) in &opts.env {
581→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
582→        }
583→
584→        args.push(name);
585→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
586→
587→        let child = tokio::process::Command::new(self.cli)
588→            .args(&args)
589→            .stdout(std::process::Stdio::piped())
590→            .stderr(std::process::Stdio::piped())
591→            .stdin(std::process::Stdio::null())
592→            .spawn()?;
593→
594→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
595→
596→        match result {
597→            Ok(Ok(output)) => {
598→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
599→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
600→
601→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
602→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
603→
604→                Ok(ExecResult {
605→                    stdout,
606→                    stderr,
607→                    exit_code: output.status.code().unwrap_or(-1),
608→                })
609→            },
610→            Ok(Err(e)) => {
611→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
612→            },
613→            Err(_) => {
614→                return Err(Error::message(format!(
615→                    "{} exec timed out after {}s",
616→                    self.cli,
617→                    opts.timeout.as_secs()
618→                )));
619→            },
620→        }
621→    }
