737→/// Return `true` when the installed Podman version supports `host-gateway`
738→/// in `--add-host` (added in Podman 5.0).
739→pub(crate) fn podman_supports_host_gateway() -> bool {
740→    let Ok(output) = std::process::Command::new("podman")
741→        .args(["version", "--format", "{{.Client.Version}}"])
742→        .output()
743→    else {
744→        return false;
745→    };
746→    let version_str = String::from_utf8_lossy(&output.stdout);
747→    let major: u32 = version_str
748→        .trim()
749→        .split('.')
750→        .next()
751→        .and_then(|s| s.parse().ok())
752→        .unwrap_or(0);
753→    major >= 5
754→}
