756→/// Resolve the host IP that a Podman container (< 5.0) can use to reach the
757→/// host.  Rootless Podman defaults to slirp4netns where the host is always
758→/// `10.0.2.2`.  Rootful Podman uses a bridge network whose gateway we query
759→/// with `podman network inspect`.
760→pub(crate) fn podman_resolve_host_ip() -> Option<String> {
761→    let rootless = std::process::Command::new("podman")
762→        .args(["info", "--format", "{{.Host.Security.Rootless}}"])
763→        .output()
764→        .ok()
765→        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string());
766→
767→    if rootless.as_deref() == Some("true") {
768→        // slirp4netns (default rootless network before Podman 5.0) maps the
769→        // host to 10.0.2.2.
770→        return Some("10.0.2.2".to_string());
771→    }
772→
773→    // Rootful — ask for the gateway of the default "podman" network.
774→    let output = std::process::Command::new("podman")
775→        .args([
776→            "network",
777→            "inspect",
778→            "podman",
779→            "--format",
780→            "{{(index .Subnets 0).Gateway}}",
781→        ])
782→        .output()
783→        .ok()?;
784→    let gateway = String::from_utf8_lossy(&output.stdout).trim().to_string();
785→    if gateway.is_empty() {
786→        None
787→    } else {
788→        Some(gateway)
789→    }
790→}
