 19→/// Cgroup v2 sandbox using `systemd-run --user --scope` (Linux only, no root required).
 20→#[cfg(target_os = "linux")]
 21→pub struct CgroupSandbox {
 22→    pub config: SandboxConfig,
 23→}
 24→
 25→#[cfg(target_os = "linux")]
 26→impl CgroupSandbox {
 27→    pub fn new(config: SandboxConfig) -> Self {
 28→        Self { config }
 29→    }
 30→
 31→    pub(crate) fn scope_name(&self, id: &SandboxId) -> String {
 32→        let prefix = self
 33→            .config
 34→            .container_prefix
 35→            .as_deref()
 36→            .unwrap_or("moltis-sandbox");
 37→        format!("{}-{}", prefix, id.key)
 38→    }
 39→
 40→    pub(crate) fn property_args(&self) -> Vec<String> {
 41→        let mut args = Vec::new();
 42→        let limits = &self.config.resource_limits;
 43→        if let Some(ref mem) = limits.memory_limit {
 44→            args.extend(["--property".to_string(), format!("MemoryMax={mem}")]);
 45→        }
 46→        if let Some(cpu) = limits.cpu_quota {
 47→            let pct = (cpu * 100.0) as u64;
 48→            args.extend(["--property".to_string(), format!("CPUQuota={pct}%")]);
 49→        }
 50→        if let Some(pids) = limits.pids_max {
 51→            args.extend(["--property".to_string(), format!("TasksMax={pids}")]);
 52→        }
 53→        args
 54→    }
 55→}
 56→
 57→#[cfg(target_os = "linux")]
 58→#[async_trait]
 59→impl Sandbox for CgroupSandbox {
 60→    fn backend_name(&self) -> &'static str {
 61→        "cgroup"
 62→    }
 63→
 64→    async fn ensure_ready(&self, _id: &SandboxId, _image_override: Option<&str>) -> Result<()> {
 65→        let output = tokio::process::Command::new("systemd-run")
 66→            .arg("--version")
 67→            .output()
 68→            .await;
 69→        match output {
 70→            Ok(o) if o.status.success() => {
 71→                debug!("systemd-run available");
 72→                Ok(())
 73→            },
 74→            _ => {
 75→                return Err(Error::message(
 76→                    "systemd-run not found; cgroup sandbox requires systemd",
 77→                ));
 78→            },
 79→        }
 80→    }
 81→
 82→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
 83→        let scope = self.scope_name(id);
 84→
 85→        let mut args = vec![
 86→            "--user".to_string(),
 87→            "--scope".to_string(),
 88→            "--unit".to_string(),
 89→            scope,
 90→        ];
 91→        args.extend(self.property_args());
 92→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
 93→
 94→        let mut cmd = tokio::process::Command::new("systemd-run");
 95→        cmd.args(&args)
 96→            .stdout(std::process::Stdio::piped())
 97→            .stderr(std::process::Stdio::piped())
 98→            .stdin(std::process::Stdio::null());
 99→
100→        if let Some(ref dir) = opts.working_dir {
101→            cmd.current_dir(dir);
102→        }
103→        for (k, v) in &opts.env {
104→            cmd.env(k, v);
105→        }
106→
107→        let child = cmd.spawn()?;
108→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
109→
110→        match result {
111→            Ok(Ok(output)) => {
112→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
113→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
114→
115→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
116→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
117→
118→                Ok(ExecResult {
119→                    stdout,
120→                    stderr,
121→                    exit_code: output.status.code().unwrap_or(-1),
122→                })
123→            },
124→            Ok(Err(e)) => {
125→                return Err(Error::message(format!("systemd-run exec failed: {e}")));
126→            },
127→            Err(_) => {
128→                return Err(Error::message(format!(
129→                    "systemd-run exec timed out after {}s",
130→                    opts.timeout.as_secs()
131→                )));
132→            },
133→        }
134→    }
135→
136→    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
137→        let scope = self.scope_name(id);
138→        let _ = tokio::process::Command::new("systemctl")
139→            .args(["--user", "stop", &format!("{scope}.scope")])
140→            .output()
141→            .await;
142→        Ok(())
143→    }
144→}
