146→/// Restricted host sandbox providing OS-level isolation (env clearing,
147→/// restricted PATH, rlimits) without containers or WASM. Commands run on the
148→/// host via `sh -c` with sanitised environment and ulimit wrappers.
149→pub struct RestrictedHostSandbox {
150→    config: SandboxConfig,
151→}
152→
153→impl RestrictedHostSandbox {
154→    pub fn new(config: SandboxConfig) -> Self {
155→        Self { config }
156→    }
157→
158→    /// Wrap a command with shell `ulimit` calls for resource isolation.
159→    fn build_ulimit_wrapped_command(&self, command: &str) -> String {
160→        let limits = &self.config.resource_limits;
161→        let mut preamble = Vec::new();
162→
163→        // Max user processes.
164→        let nproc = limits.pids_max.map(u64::from).unwrap_or(256);
165→        preamble.push(format!("ulimit -u {nproc} 2>/dev/null"));
166→
167→        // Max open file descriptors.
168→        preamble.push("ulimit -n 1024 2>/dev/null".to_string());
169→
170→        // CPU time in seconds.
171→        let cpu_secs = limits
172→            .cpu_quota
173→            .map(|q| q.ceil() as u64 * 60)
174→            .unwrap_or(300);
175→        preamble.push(format!("ulimit -t {cpu_secs} 2>/dev/null"));
176→
177→        // Virtual memory (in KB for ulimit -v).
178→        let mem_bytes = limits
179→            .memory_limit
180→            .as_deref()
181→            .and_then(parse_memory_limit)
182→            .unwrap_or(512 * 1024 * 1024);
183→        let mem_kb = mem_bytes / 1024;
184→        preamble.push(format!("ulimit -v {mem_kb} 2>/dev/null"));
185→
186→        format!("{}; {command}", preamble.join("; "))
187→    }
188→}
189→
190→/// Parse a human-readable memory limit like "512M" or "1G" into bytes.
191→pub(crate) fn parse_memory_limit(s: &str) -> Option<u64> {
192→    let s = s.trim();
193→    let (num_part, multiplier) =
194→        if let Some(n) = s.strip_suffix('G').or_else(|| s.strip_suffix('g')) {
195→            (n, 1024 * 1024 * 1024)
196→        } else if let Some(n) = s.strip_suffix('M').or_else(|| s.strip_suffix('m')) {
197→            (n, 1024 * 1024)
198→        } else if let Some(n) = s.strip_suffix('K').or_else(|| s.strip_suffix('k')) {
199→            (n, 1024)
200→        } else {
201→            (s, 1)
202→        };
203→    num_part.trim().parse::<u64>().ok().map(|n| n * multiplier)
204→}
205→
206→#[async_trait]
207→impl Sandbox for RestrictedHostSandbox {
208→    fn backend_name(&self) -> &'static str {
209→        "restricted-host"
210→    }
211→
212→    fn is_real(&self) -> bool {
213→        true
214→    }
215→
216→    async fn ensure_ready(&self, _id: &SandboxId, _image_override: Option<&str>) -> Result<()> {
217→        Ok(())
218→    }
219→
220→    async fn exec(&self, _id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
221→        // Wrap the command with shell ulimit calls for resource isolation.
222→        let wrapped = self.build_ulimit_wrapped_command(command);
223→
224→        let mut cmd = tokio::process::Command::new("sh");
225→        cmd.args(["-c", &wrapped]);
226→
227→        // Scrub all inherited env vars for isolation.
228→        cmd.env_clear();
229→
230→        // Set minimal safe environment.
231→        cmd.env("PATH", "/usr/local/bin:/usr/bin:/bin");
232→        cmd.env("HOME", "/tmp");
233→        cmd.env("LANG", "C.UTF-8");
234→
235→        // Apply user-specified env vars.
236→        for (k, v) in &opts.env {
237→            cmd.env(k, v);
238→        }
239→
240→        if let Some(ref dir) = opts.working_dir {
241→            cmd.current_dir(dir);
242→        }
243→
244→        cmd.stdout(std::process::Stdio::piped())
245→            .stderr(std::process::Stdio::piped())
246→            .stdin(std::process::Stdio::null());
247→
248→        let child = cmd.spawn()?;
249→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
250→
251→        match result {
252→            Ok(Ok(output)) => {
253→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
254→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
255→
256→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
257→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
258→
259→                Ok(ExecResult {
260→                    stdout,
261→                    stderr,
262→                    exit_code: output.status.code().unwrap_or(-1),
263→                })
264→            },
265→            Ok(Err(e)) => {
266→                return Err(Error::message(format!(
267→                    "restricted-host sandbox exec failed: {e}"
268→                )));
269→            },
270→            Err(_) => {
271→                return Err(Error::message(format!(
272→                    "restricted-host sandbox exec timed out after {}s",
273→                    opts.timeout.as_secs()
274→                )));
275→            },
276→        }
277→    }
278→
279→    async fn read_file(
280→        &self,
281→        _id: &SandboxId,
282→        file_path: &str,
283→        max_bytes: u64,
284→    ) -> Result<SandboxReadResult> {
285→        native_host_read_file(file_path, max_bytes).await
286→    }
287→
288→    async fn write_file(
289→        &self,
290→        _id: &SandboxId,
291→        file_path: &str,
292→        content: &[u8],
293→    ) -> Result<Option<serde_json::Value>> {
294→        native_host_write_file(file_path, content).await
