 36→/// Wrapper sandbox that can fail over from a primary backend to a fallback backend.
 37→///
 38→/// This is used on macOS to fail over from Apple Container to Docker when the
 39→/// Apple runtime enters a corrupted state (stale metadata, missing config.json,
 40→/// service errors, etc.).
 41→pub struct FailoverSandbox {
 42→    primary: Arc<dyn Sandbox>,
 43→    fallback: Arc<dyn Sandbox>,
 44→    primary_name: &'static str,
 45→    fallback_name: &'static str,
 46→    use_fallback: RwLock<bool>,
 47→}
 48→
 49→impl FailoverSandbox {
 50→    pub fn new(primary: Arc<dyn Sandbox>, fallback: Arc<dyn Sandbox>) -> Self {
 51→        let primary_name = primary.backend_name();
 52→        let fallback_name = fallback.backend_name();
 53→        Self {
 54→            primary,
 55→            fallback,
 56→            primary_name,
 57→            fallback_name,
 58→            use_fallback: RwLock::new(false),
 59→        }
 60→    }
 61→
 62→    async fn fallback_enabled(&self) -> bool {
 63→        *self.use_fallback.read().await
 64→    }
 65→
 66→    async fn switch_to_fallback(&self, error: &Error) {
 67→        let mut use_fallback = self.use_fallback.write().await;
 68→        if !*use_fallback {
 69→            warn!(
 70→                primary = self.primary_name,
 71→                fallback = self.fallback_name,
 72→                %error,
 73→                "sandbox primary backend failed, switching to fallback backend"
 74→            );
 75→            *use_fallback = true;
 76→        }
 77→    }
 78→
 79→    fn should_failover(&self, error: &Error) -> bool {
 80→        let message = format!("{error:#}");
 81→        match self.primary_name {
 82→            "apple-container" => is_apple_container_corruption_error(&message),
 83→            "docker" => is_docker_failover_error(&message),
 84→            "podman" => is_podman_failover_error(&message),
 85→            _ => false,
 86→        }
 87→    }
 88→}
 89→
 90→#[async_trait]
 91→impl Sandbox for FailoverSandbox {
 92→    fn backend_name(&self) -> &'static str {
 93→        self.primary_name
 94→    }
 95→
 96→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
 97→        if self.fallback_enabled().await {
 98→            return self.fallback.ensure_ready(id, image_override).await;
 99→        }
