 66→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
 67→#[serde(rename_all = "lowercase")]
 68→#[derive(Default)]
 69→pub enum SandboxScope {
 70→    #[default]
 71→    Session,
 72→    Agent,
 73→    Shared,
 74→}
 75→
 76→impl std::fmt::Display for SandboxScope {
 77→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 78→        match self {
 79→            Self::Session => f.write_str("session"),
 80→            Self::Agent => f.write_str("agent"),
 81→            Self::Shared => f.write_str("shared"),
 82→        }
 83→    }
 84→}
