692→/// E2E regression test for #796: Podman+BuildKit may leave images in
693→/// BuildKit's cache instead of the Podman store.  Gated behind
694→/// `MOLTIS_SANDBOX_RUNTIME_E2E=1` and requires Podman to be installed.
695→#[tokio::test]
696→async fn test_podman_build_image_exists_in_store() {
697→    let enabled = env::var("MOLTIS_SANDBOX_RUNTIME_E2E")
698→        .map(|v| matches!(v.trim().to_ascii_lowercase().as_str(), "1" | "true" | "yes"))
699→        .unwrap_or(false);
700→    if !enabled || !is_cli_available("podman") {
701→        eprintln!(
702→            "skipping test_podman_build_image_exists_in_store (set MOLTIS_SANDBOX_RUNTIME_E2E=1 and install podman)"
703→        );
704→        return;
705→    }
706→
707→    let sandbox = DockerSandbox::podman(SandboxConfig::default());
708→    let packages = vec!["curl".into()];
709→    let tag = sandbox_image_tag(sandbox.image_repo(), "ubuntu:25.10", &packages);
710→
711→    // Remove any pre-existing image so we exercise the full build path.
712→    let _ = tokio::process::Command::new("podman")
713→        .args(["rmi", "-f", &tag])
714→        .output()
715→        .await;
716→
717→    let result = sandbox
718→        .build_image("ubuntu:25.10", &packages)
719→        .await
