274→    async fn resolve_local_image(&self, requested_image: &str) -> Result<String> {
275→        if sandbox_image_exists(self.cli, requested_image).await {
276→            debug!(image = requested_image, "sandbox image found locally");
277→            return Ok(requested_image.to_string());
278→        }
279→
280→        let base_image = self.image().to_string();
281→        let packages = self.config.packages.clone();
282→        let Some(rebuild_tag) = rebuildable_sandbox_image_tag(
283→            requested_image,
284→            self.image_repo(),
285→            &base_image,
286→            &packages,
287→        ) else {
288→            return Ok(requested_image.to_string());
289→        };
290→
291→        if requested_image == rebuild_tag {
292→            info!(
293→                image = requested_image,
294→                "sandbox image missing locally, rebuilding on demand"
295→            );
296→        } else {
297→            warn!(
298→                requested = requested_image,
299→                rebuilt = %rebuild_tag,
300→                "requested sandbox image missing locally, using deterministic tag from current config"
301→            );
302→        }
303→
304→        let Some(result) = self.build_image(&base_image, &packages).await? else {
305→            return Ok(requested_image.to_string());
306→        };
307→        Ok(result.tag)
308→    }
309→
310→    /// Export an image from BuildKit's cache into the Podman store.
311→    ///
312→    /// When Podman delegates `podman build` to a BuildKit daemon the image may
313→    /// land only in BuildKit's internal cache.  This method re-runs the build
314→    /// with `--output type=docker,dest=<file>` (a BuildKit cache-hit, so
315→    /// essentially free) and pipes the tarball into `podman load`.
316→    async fn export_buildkit_image_to_store(
317→        &self,
318→        tag: &str,
319→        dockerfile_path: &std::path::Path,
320→        context_dir: &std::path::Path,
321→    ) -> Result<()> {
322→        let tar_path = std::env::temp_dir().join(format!(
323→            "moltis-sandbox-export-{}.tar",
324→            uuid::Uuid::new_v4()
325→        ));
326→
327→        // Re-build with docker-archive output.  The `-t` flag embeds the
328→        // correct tag in the archive so `podman load` names it correctly.
329→        // BuildKit's layer cache makes this a near-instant cache hit for the
330→        // same Dockerfile.
331→        let export_output = tokio::process::Command::new(self.cli)
332→            .args([
333→                "build",
334→                "--output",
335→                &format!("type=docker,dest={}", tar_path.display()),
336→                "-t",
337→                tag,
338→                "-f",
339→            ])
340→            .arg(dockerfile_path)
341→            .arg(context_dir)
342→            .stdout(std::process::Stdio::piped())
343→            .stderr(std::process::Stdio::piped())
344→            .output()
345→            .await?;
346→
347→        if !export_output.status.success() {
348→            let _ = std::fs::remove_file(&tar_path);
349→            let stderr = String::from_utf8_lossy(&export_output.stderr);
350→            return Err(Error::message(format!(
351→                "podman build --output failed for {tag}: {}",
352→                stderr.trim()
353→            )));
354→        }
355→
356→        // Load the tarball into the Podman store.
357→        let load_output = tokio::process::Command::new(self.cli)
358→            .args(["load", "-i"])
359→            .arg(&tar_path)
360→            .stdout(std::process::Stdio::piped())
361→            .stderr(std::process::Stdio::piped())
362→            .output()
363→            .await?;
364→
365→        let _ = std::fs::remove_file(&tar_path);
366→
367→        if !load_output.status.success() {
368→            let stderr = String::from_utf8_lossy(&load_output.stderr);
369→            return Err(Error::message(format!(
370→                "podman load failed for {tag}: {}",
371→                stderr.trim()
372→            )));
373→        }
374→
375→        // Final verification.
376→        if !sandbox_image_exists(self.cli, tag).await {
377→            return Err(Error::message(format!(
378→                "image {tag} still missing from podman store after BuildKit export"
379→            )));
380→        }
381→
382→        info!(tag, "successfully exported BuildKit image to podman store");
383→        Ok(())
384→    }
385→}
386→
387→#[async_trait]
388→impl Sandbox for DockerSandbox {
389→    fn backend_name(&self) -> &'static str {
390→        self.backend_label
391→    }
392→
393→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
394→        let name = self.container_name(id);
395→
396→        // Check if container already running.
397→        let check = tokio::process::Command::new(self.cli)
398→            .args(["inspect", "--format", "{{.State.Running}}", &name])
399→            .output()
400→            .await;
401→
402→        if let Ok(output) = check {
403→            let stdout = String::from_utf8_lossy(&output.stdout);
404→            if stdout.trim() == "true" {
405→                debug!(container = %name, "sandbox container already running");
406→                return Ok(());
407→            }
408→        }
409→
410→        // Resolve image first so we know whether it's prebuilt (affects hardening).
411→        let requested_image = image_override.unwrap_or_else(|| self.image());
412→        let image = self.resolve_local_image(requested_image).await?;
413→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
414→        debug!(container = %name, %image, is_prebuilt, "resolved sandbox image");
415→
416→        // Start a new container.
417→        info!(container = %name, %image, "starting new sandbox container");
418→        let mut args = vec![
419→            "run".to_string(),
420→            "-d".to_string(),
421→            "--name".to_string(),
422→            name.clone(),
423→        ];
424→
425→        args.extend(self.network_run_args());
426→
427→        if let Some(ref tz) = self.config.timezone {
428→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
429→        }
430→
431→        args.extend(self.resource_args());
432→        args.extend(Self::hardening_args(is_prebuilt, self.kind));
433→        args.extend(self.workspace_args());
434→        args.extend(self.home_persistence_args(id)?);
435→
436→        args.push(image.clone());
437→        args.extend(["sleep".to_string(), "infinity".to_string()]);
438→
439→        let output = tokio::process::Command::new(self.cli)
440→            .args(&args)
441→            .output()
442→            .await?;
443→
444→        if !output.status.success() {
445→            let stderr = String::from_utf8_lossy(&output.stderr);
446→            return Err(Error::message(format!(
447→                "{} run failed: {}",
448→                self.cli,
449→                stderr.trim()
450→            )));
451→        }
452→
453→        // Skip provisioning if the image is a pre-built instance sandbox image
454→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
455→        if !is_prebuilt {
456→            let needs_provisioning = {
457→                let mut provisioned = self.provisioned.lock().await;
458→                if provisioned.contains(&name) {
459→                    false
460→                } else {
461→                    provisioned.insert(name.clone());
462→                    true
463→                }
464→            };
465→            if needs_provisioning {
466→                if let Err(e) = provision_packages(self.cli, &name, &self.config.packages).await {
467→                    self.provisioned.lock().await.remove(&name);
468→                    return Err(e);
469→                }
470→            } else {
471→                debug!(
472→                    container = %name,
473→                    "skipping provisioning, already completed for container"
474→                );
475→            }
476→        }
477→
478→        Ok(())
479→    }
480→
481→    async fn build_image(
482→        &self,
483→        base: &str,
484→        packages: &[String],
485→    ) -> Result<Option<BuildImageResult>> {
486→        if packages.is_empty() {
487→            return Ok(None);
488→        }
489→
490→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
491→
492→        // Check if image already exists.
493→        if sandbox_image_exists(self.cli, &tag).await {
494→            info!(
495→                tag,
496→                "pre-built sandbox image already exists, skipping build"
497→            );
498→            return Ok(Some(BuildImageResult { tag, built: false }));
499→        }
500→
501→        // Generate Dockerfile in a temp dir.
502→        let tmp_dir =
503→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
504→        std::fs::create_dir_all(&tmp_dir)?;
505→
506→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
507→        let dockerfile = sandbox_image_dockerfile(base, packages);
508→        let dockerfile_path = tmp_dir.join("Dockerfile");
509→        std::fs::write(&dockerfile_path, &dockerfile)?;
510→
511→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
512→
513→        let output = tokio::process::Command::new(self.cli)
514→            .args(["build", "-t", &tag, "-f"])
515→            .arg(&dockerfile_path)
516→            .arg(&tmp_dir)
517→            .stdout(std::process::Stdio::piped())
518→            .stderr(std::process::Stdio::piped())
519→            .output()
520→            .await;
521→
522→        let output = output?;
523→        if !output.status.success() {
524→            let _ = std::fs::remove_dir_all(&tmp_dir);
525→            let stdout = String::from_utf8_lossy(&output.stdout);
526→            let stderr = String::from_utf8_lossy(&output.stderr);
527→            warn!(
528→                tag,
529→                stdout = %tail_lines(&stdout, 20),
530→                stderr = %stderr.trim(),
531→                "{} build failed",
532→                self.cli,
533→            );
534→            return Err(Error::message(format!(
535→                "{} build failed for {tag}: {}",
536→                self.cli,
537→                stderr.trim()
538→            )));
539→        }
540→
541→        let stdout = String::from_utf8_lossy(&output.stdout);
542→        debug!(tag, output = %tail_lines(&stdout, 20), "docker build output");
543→
544→        // Podman with BuildKit: the build may succeed (exit 0) but leave the
545→        // image in BuildKit's internal cache instead of the Podman store.
546→        // Verify the image is actually present and recover if not.
547→        if self.kind == BackendKind::Podman && !sandbox_image_exists(self.cli, &tag).await {
548→            warn!(
549→                tag,
550→                "podman build succeeded but image missing from store \
551→                 (likely BuildKit delegation), exporting via tarball"
552→            );
553→            let export_result = self
554→                .export_buildkit_image_to_store(&tag, &dockerfile_path, &tmp_dir)
555→                .await;
556→            // Clean up temp dir regardless of export result.
557→            let _ = std::fs::remove_dir_all(&tmp_dir);
558→            export_result?;
559→        } else {
560→            let _ = std::fs::remove_dir_all(&tmp_dir);
561→        }
562→
563→        info!(tag, "pre-built sandbox image ready");
564→        Ok(Some(BuildImageResult { tag, built: true }))
565→    }
566→
567→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
568→        let name = self.container_name(id);
569→
570→        let mut args = vec!["exec".to_string()];
571→
572→        if let Some(ref dir) = opts.working_dir {
573→            args.extend(["-w".to_string(), dir.display().to_string()]);
574→        }
575→
576→        // Inject proxy env vars so traffic routes through the trusted-network
577→        // proxy running on the host.
578→        args.extend(self.proxy_exec_env_args());
579→
580→        for (k, v) in &opts.env {
581→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
582→        }
583→
584→        args.push(name);
585→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
586→
587→        let child = tokio::process::Command::new(self.cli)
588→            .args(&args)
589→            .stdout(std::process::Stdio::piped())
590→            .stderr(std::process::Stdio::piped())
591→            .stdin(std::process::Stdio::null())
592→            .spawn()?;
593→
594→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
595→
596→        match result {
597→            Ok(Ok(output)) => {
598→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
599→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
600→
601→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
602→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
603→
604→                Ok(ExecResult {
605→                    stdout,
606→                    stderr,
607→                    exit_code: output.status.code().unwrap_or(-1),
608→                })
609→            },
610→            Ok(Err(e)) => {
611→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
612→            },
613→            Err(_) => {
614→                return Err(Error::message(format!(
615→                    "{} exec timed out after {}s",
616→                    self.cli,
617→                    opts.timeout.as_secs()
618→                )));
619→            },
620→        }
621→    }
622→
623→    async fn read_file(
624→        &self,
625→        id: &SandboxId,
626→        file_path: &str,
627→        max_bytes: u64,
628→    ) -> Result<SandboxReadResult> {
629→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
630→            return native_host_read_file(
631→                host_path
632→                    .to_str()
633→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
634→                max_bytes,
635→            )
636→            .await;
637→        }
638→
639→        let container_name = self.container_name(id);
640→        oci_container_read_file(self.cli, &container_name, file_path, max_bytes).await
641→    }
642→
643→    async fn write_file(
644→        &self,
645→        id: &SandboxId,
646→        file_path: &str,
647→        content: &[u8],
648→    ) -> Result<Option<serde_json::Value>> {
649→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
650→            return native_host_write_file(
651→                host_path
652→                    .to_str()
653→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
654→                content,
655→            )
656→            .await;
657→        }
658→
659→        let container_name = self.container_name(id);
660→        oci_container_write_file(self.cli, &container_name, file_path, content).await
661→    }
662→
663→    async fn list_files(&self, id: &SandboxId, root: &str) -> Result<SandboxListFilesResult> {
664→        if let Some(host_path) = self.mounted_host_path(id, root) {
665→            let host_files = native_host_list_files(
666→                host_path
667→                    .to_str()
668→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
669→            )
670→            .await?;
671→            return remap_host_list_result_to_guest(root, &host_path, host_files);
672→        }
673→
674→        let container_name = self.container_name(id);
675→        oci_container_list_files(self.cli, &container_name, root).await
676→    }
677→
678→    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
679→        let name = self.container_name(id);
680→        self.provisioned.lock().await.remove(&name);
681→        let _ = tokio::process::Command::new(self.cli)
682→            .args(["rm", "-f", &name])
683→            .output()
684→            .await;
685→        Ok(())
686→    }
687→}
