 59→impl Sandbox for CgroupSandbox {
 60→    fn backend_name(&self) -> &'static str {
 61→        "cgroup"
 62→    }
 63→
 64→    async fn ensure_ready(&self, _id: &SandboxId, _image_override: Option<&str>) -> Result<()> {
 65→        let output = tokio::process::Command::new("systemd-run")
 66→            .arg("--version")
 67→            .output()
 68→            .await;
 69→        match output {
 70→            Ok(o) if o.status.success() => {
 71→                debug!("systemd-run available");
 72→                Ok(())
 73→            },
 74→            _ => {
 75→                return Err(Error::message(
 76→                    "systemd-run not found; cgroup sandbox requires systemd",
 77→                ));
 78→            },
 79→        }
 80→    }
