    );
    assert!(args.contains(&"/sys/firmware:ro,nosuid".to_string()));
    assert!(args.contains(&"/sys/class/dmi:ro,nosuid".to_string()));
    assert!(args.contains(&"/sys/devices/virtual/dmi:ro,nosuid".to_string()));
